INSERT INTO settings (org_name,email_sender_name,min_age_threshold,allow_external_internal_jobs,session_timeout_minutes,closing_soon_days,max_applications_per_candidate,notif_template_shortlist,notif_template_decline,notif_template_interview,notif_template_offer) VALUES ('Uganda Civil Aviation Authority','CAA HR Team',21,0,30,7,5,'Dear {name}, we are pleased to inform you that your application for {role} has been shortlisted. Our team will contact you with further instructions shortly.','Dear {name}, thank you for applying for {role}. After careful review, we regret to inform you that your application has not been successful at this stage.','Dear {name}, congratulations! Your application for {role} has progressed to the interview stage. Our HR team will contact you to confirm the date and time.','Dear {name}, we are delighted to offer you the position of {role}. Please review the attached offer letter and respond within five (5) working days.');
